VALUES
  ('social-worker-moex-07160', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在與兒童及其家庭工作時，下列何者錯誤？', '["必須思索問題對家庭所有成員的意義與重要性", "所提供的服務需能被家長接受", "要保有拯救兒童的心態", "必須中立、客觀，且能敏感自己的情緒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07161', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會功能（social function）是社工專業助人的重點與價值偏好。請挑出Boehm對社會功能的正確敘述？', '["它是個人所扮演的好幾種角色的主要活動表現", "它來自個人在先賦團體（ascribed group）中的成員身分而被要求實踐", "儘管人因成長階段有不同角色，但其社會功能表現不變", "社會功能概念等同人際關係概念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07162', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者是任務中心取向的基本假定（assumption）之一？', '["人有改變動力，但只想減輕困難到可忍受為止", "個人的問題起因於其慣用方式無法處理內在壓力或外在事件", "個人問題和社會政治條件彼此相關", "任何事情都有原因"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07163', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於個案工作、團體工作與社區工作三大方法異同的敘述，下列何者錯誤？', '["獲得社會工作界認可為專業技術的先後順序是：個案、團體、社區", "個案工作實務的中心觀點是「人在情境中」；社區工作實務的中心觀點是「社會學習理論」", "三大方法的先鋒運動均起源於英國「慈善組織會社」", "在專業倫理與獨特性上的原則是相似的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07164', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關決定團體規模的原則，下列何者錯誤？', '["團體要能圍坐而相互看到對方，聽到對方聲音為原則", "團體大到使成員能得到刺激，小到足夠參與個人認知為原則", "如果團體必須較大時，就要將結構分化", "開放性團體可以不太在意成員多寡；封閉性團體成員多寡卻很重要，以避免成員流失而解散"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07165', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關「設定目標」的敘述，何者錯誤？', '["社會工作者必須鼓勵案主一起參與目標的設定", "目標的設定需以過程而非結果的形式作敘述", "有效的目標應與案主的價值及文化具有一致性", "有效的目標應該是具有時間限制的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07166', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於生態理論的敘述，下列何者錯誤？', '["個人與環境中的他人系統會維持一種持續性的交流", "透過系統的交流過程，系統和個人也不斷彼此影響", "社會中的每一個系統都有相同的情境，以利社會工作的處置", "人面對環境的刺激是一個反應者，也會主動影響所處環境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07167', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「社區個案工作」比一般的「社會個案工作」更重視那一方面的能力？', '["諮商輔導能力", "方案目標的擬訂能力", "社區案主的自我充權能力", "社區資源的連結運用能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07168', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關團體工作定義的敘述，何者錯誤？', '["團體是存在於運作的場域之中，團體成員與領導者所形成的力量，是影響團體工作成效的唯一關鍵因素", "團體工作是工作者有計畫、循序漸進的執行各種活動，以達團體工作的各項目的", "不論是何種型態的團體工作，都會重視成員社會情緒需求的滿足與任務的達成", "工作者在團體運作過程中，應協助成員發展各種能力，使他們可以為團體的運作及發展擔負更多責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07169', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作的最後一個階段常有許多重要的工作內容，下列有關團體結束階段的敘述，何者錯誤？', '["團體結束階段，從各層面評估團體的成效，是工作者重要的工作之一", "工作者在最後一次團體之前，先行預告成員團體即將結束，這是處理成員分離焦慮的技巧之一", "任務性團體在結束階段要重視的是團體任務的成果，而非聚焦在成員分離的情緒反應", "任務性團體成員在結束階段，終止關係對其帶來的影響，和處遇性團體成員是一致的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
